    return {"name": name.strip().title(), "score": int(score), "email": email.strip().lower()}

records = []
with open("data/roster.csv") as file:
    next(file)
    for line in file:
        # Keep using clean_row(line), but only save rows with valid scores.
        # Skip ValueError rows so the roster cleaner can finish the file.
        try:
            records.append(clean_row(line))
        except ValueError:
            pass

